class HybridWebViewActivity : ComponentActivity() {

    private lateinit var webView: HybridWebView
    private lateinit var bridge: NativeBridge

    private val cameraPermissionLauncher =
        registerForActivityResult(ActivityResultContracts.RequestPermission()) { granted ->
            bridge.onCameraPermissionResult(granted)
        }

    private val notificationPermissionLauncher =
        registerForActivityResult(ActivityResultContracts.RequestPermission()) { granted ->
            bridge.onNotificationPermissionResult(granted)
        }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        webView = HybridWebView(this)
        bridge = NativeBridge(
            activity = this,
            webView = webView,
            requestCameraPermission = {
                requestCameraPermissionIfNeeded()
            },
            requestNotificationPermission = {
                requestNotificationPermissionIfNeeded()
            }
        )
        webView.attachBridge(bridge)

        val container = FrameLayout(this).apply {
            addView(
                webView,
                FrameLayout.LayoutParams(
                    FrameLayout.LayoutParams.MATCH_PARENT,
                    FrameLayout.LayoutParams.MATCH_PARENT
                )
            )
        }
        setContentView(container)

        val initialUrl = intent?.getStringExtra(EXTRA_URL) ?: DEFAULT_URL
        if (savedInstanceState == null) {
            webView.loadUrl(initialUrl)
        }
    }

    private fun requestCameraPermissionIfNeeded() {
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) ==
            PackageManager.PERMISSION_GRANTED
        ) {
            bridge.onCameraPermissionResult(true)
        } else {
            cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
        }
    }

    private fun requestNotificationPermissionIfNeeded() {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU) {
            bridge.onNotificationPermissionResult(true)
            return
        }
        if (ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS) ==
            PackageManager.PERMISSION_GRANTED
        ) {
            bridge.onNotificationPermissionResult(true)
        } else {
            notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
        }
    }

    override fun onResume() {
        super.onResume()
        webView.onResume()
        webView.resumeTimers()
    }

    override fun onPause() {
        webView.onPause()
        webView.pauseTimers()
        super.onPause()
    }

    override fun onDestroy() {
        webView.cleanup()
        super.onDestroy()
    }

    override fun onSaveInstanceState(outState: Bundle) {
        super.onSaveInstanceState(outState)
        webView.saveState(outState)
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    companion object {
        const val EXTRA_URL = "extra_url"
        const val DEFAULT_URL = "https://your-mobile-web-app.example.com"
    }
}

@SuppressLint("SetJavaScriptEnabled")
class HybridWebView(context: Context) : WebView(context) {

    private var bridge: NativeBridge? = null

    init {
        configure()
    }

    fun attachBridge(nativeBridge: NativeBridge) {
        bridge = nativeBridge
        addJavascriptInterface(nativeBridge, NativeBridge.JS_BRIDGE_NAME)
    }

    private fun configure() {
        settings.javaScriptEnabled = true
        settings.domStorageEnabled = true
        settings.databaseEnabled = true
        settings.allowFileAccess = true
        settings.allowContentAccess = true
        settings.mediaPlaybackRequiresUserGesture = false
        settings.loadsImagesAutomatically = true
        settings.cacheMode = WebSettings.LOAD_DEFAULT
        settings.mixedContentMode = WebSettings.MIXED_CONTENT_COMPATIBILITY_MODE
        settings.javaScriptCanOpenWindowsAutomatically = true
        settings.setSupportMultipleWindows(false)
        settings.builtInZoomControls = false
        settings.displayZoomControls = false
        settings.useWideViewPort = true
        settings.loadWithOverviewMode = true
        settings.userAgentString = settings.userAgentString + " HybridWebView/1.0"

        CookieManager.getInstance().setAcceptCookie(true)
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
            CookieManager.getInstance().setAcceptThirdPartyCookies(this, true)
        }

        webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                return false
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
                bridge?.emitEvent(
                    "pageLoaded",
                    JSONObject().apply {
                        put("url", url ?: "")
                    }
                )
            }
        }

        webChromeClient = object : WebChromeClient() {
            override fun onPermissionRequest(request: PermissionRequest?) {
                request ?: return
                val resources = request.resources?.toList().orEmpty()
                val grantList = mutableListOf<String>()

                if (resources.contains(PermissionRequest.RESOURCE_VIDEO_CAPTURE)) {
                    grantList.add(PermissionRequest.RESOURCE_VIDEO_CAPTURE)
                }
                if (resources.contains(PermissionRequest.RESOURCE_AUDIO_CAPTURE)) {
                    grantList.add(PermissionRequest.RESOURCE_AUDIO_CAPTURE)
                }

                if (grantList.isNotEmpty()) {
                    request.grant(grantList.toTypedArray())
                } else {
                    request.deny()
                }
            }

            override fun onGeolocationPermissionsShowPrompt(
                origin: String?,
                callback: GeolocationPermissions.Callback?
            ) {
                callback?.invoke(origin, true, false)
            }

            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                filePathCallback?.onReceiveValue(null)
                return true
            }
        }
    }

    fun cleanup() {
        removeJavascriptInterface(NativeBridge.JS_BRIDGE_NAME)
        stopLoading()
        loadUrl("about:blank")
        clearHistory()
        removeAllViews()
        destroy()
    }
}

@Keep
class NativeBridge(
    private val activity: Activity,
    private val webView: WebView,
    private val requestCameraPermission: () -> Unit,
    private val requestNotificationPermission: () -> Unit
) {

    private val prefs = activity.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    @Volatile
    private var pendingCameraRequestId: String? = null

    @Volatile
    private var pendingNotificationRequestId: String? = null

    @JavascriptInterface
    fun cameraAccess(requestId: String?) {
        pendingCameraRequestId = requestId ?: ""
        requestCameraPermission.invoke()
    }

    @JavascriptInterface
    fun requestPushNotifications(requestId: String?) {
        pendingNotificationRequestId = requestId ?: ""
        requestNotificationPermission.invoke()
    }

    @JavascriptInterface
    fun setLocalStorageItem(key: String?, value: String?) {
        if (key.isNullOrEmpty()) return
        prefs.edit { putString(key, value) }
    }

    @JavascriptInterface
    fun getLocalStorageItem(key: String?, requestId: String?) {
        if (key.isNullOrEmpty()) {
            emitCallback(
                requestId,
                false,
                JSONObject().apply { put("error", "Key is required") }
            )
            return
        }
        val value = prefs.getString(key, null)
        emitCallback(
            requestId,
            true,
            JSONObject().apply {
                put("key", key)
                put("value", value)
            }
        )
    }

    @JavascriptInterface
    fun removeLocalStorageItem(key: String?) {
        if (key.isNullOrEmpty()) return
        prefs.edit { remove(key) }
    }

    @JavascriptInterface
    fun clearLocalStorage() {
        prefs.edit { clear() }
    }

    @JavascriptInterface
    fun getAllLocalStorage(requestId: String?) {
        val all = prefs.all
        val data = JSONObject()
        all.forEach { (key, value) ->
            data.put(key, value)
        }
        emitCallback(
            requestId,
            true,
            JSONObject().apply {
                put("items", data)
            }
        )
    }

    @JavascriptInterface
    fun getPushToken(requestId: String?) {
        val token = prefs.getString(KEY_PUSH_TOKEN, null)
        emitCallback(
            requestId,
            true,
            JSONObject().apply {
                put("token", token)
            }
        )
    }

    @JavascriptInterface
    fun setPushToken(token: String?) {
        prefs.edit { putString(KEY_PUSH_TOKEN, token) }
        emitEvent(
            "pushTokenUpdated",
            JSONObject().apply {
                put("token", token)
            }
        )
    }

    @JavascriptInterface
    fun getDeviceInfo(requestId: String?) {
        emitCallback(
            requestId,
            true,
            JSONObject().apply {
                put("platform", "android")
                put("sdkInt", Build.VERSION.SDK_INT)
                put("manufacturer", Build.MANUFACTURER)
                put("brand", Build.BRAND)
                put("model", Build.MODEL)
                put("versionRelease", Build.VERSION.RELEASE ?: "")
            }
        )
    }

    fun onCameraPermissionResult(granted: Boolean) {
        val requestId = pendingCameraRequestId
        pendingCameraRequestId = null
        emitCallback(
            requestId,
            granted,
            JSONObject().apply {
                put("granted", granted)
                put("feature", "camera")
                if (granted) {
                    put("captureDir", createImageDirectory().absolutePath)
                }
            }
        )
    }

    fun onNotificationPermissionResult(granted: Boolean) {
        val requestId = pendingNotificationRequestId
        pendingNotificationRequestId = null
        emitCallback(
            requestId,
            granted,
            JSONObject().apply {
                put("granted", granted)
                put("feature", "pushNotifications")
            }
        )
    }

    fun emitEvent(event: String, payload: JSONObject = JSONObject()) {
        val script = """
            window.HybridApp && window.HybridApp._nativeEvent && 
            window.HybridApp._nativeEvent(${JSONObject().apply {
                put("event", event)
                put("payload", payload)
            }.toString()});
        """.trimIndent()
        evaluate(script)
    }

    private fun emitCallback(requestId: String?, success: Boolean, payload: JSONObject) {
        val script = """
            window.HybridApp && window.HybridApp._nativeCallback && 
            window.HybridApp._nativeCallback(${JSONObject().apply {
                put("requestId", requestId ?: "")
                put("success", success)
                put("payload", payload)
            }.toString()});
        """.trimIndent()
        evaluate(script)
    }

    private fun evaluate(js: String) {
        activity.runOnUiThread {
            webView.evaluateJavascript(js, null)
        }
    }

    private fun createImageDirectory(): File {
        val parent = activity.getExternalFilesDir(Environment.DIRECTORY_PICTURES)
            ?: activity.filesDir
        val dir = File(parent, "hybrid_camera")
        if (!dir.exists()) dir.mkdirs()
        val stamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
        File(dir, "IMG_$stamp.jpg")
        return dir
    }

    companion object {
        const val JS_BRIDGE_NAME = "NativeBridge"
        private const val PREFS_NAME = "hybrid_webview_storage"
        private const val KEY_PUSH_TOKEN = "push_token"
    }
}

